def utcnow_iso():
    return datetime.now(timezone.utc).isoformat()


def normalize_url(raw: str) -> str:
    raw = (raw or "").strip()
    if not raw:
        raise ValueError("missing url")
    if len(raw) > MAX_URL_LENGTH:
        raise ValueError("url too long")

    if not re.match(r"^[a-zA-Z][a-zA-Z0-9+\-.]*://", raw):
        raw = "https://" + raw

    u = urlparse(raw)
    if u.scheme not in ("http", "https"):
        raise ValueError("unsupported scheme")

    if not u.netloc:
        raise ValueError("invalid url")

    host = u.hostname or ""
    if not ALLOW_PRIVATE_IPS:
        if host.startswith("[") and host.endswith("]"):
            host_check = host
        else:
            host_check = host
        for rx in PRIVATE_NETS:
            if rx.search(host_check):
                raise ValueError("private or loopback host not allowed")

    port = u.port
    if port and port not in (80, 443):
        pass

    u2 = u._replace(fragment="")
    return urlunparse(u2)


def cache_get(url: str):
    now = time.time()
    with recent_cache_lock:
        item = recent_cache.get(url)
        if not item:
            return None
        if item["expires_at"] < now:
            del recent_cache[url]
            return None
        return item


def cache_set(url: str, payload: dict, ttl: int):
    now = time.time()
    with recent_cache_lock:
        recent_cache[url] = {"expires_at": now + ttl, "payload": payload}


def content_type_for(fmt: str) -> str:
    if fmt == "png":
        return "image/png"
    return "image/jpeg"


def make_key(url: str, fmt: str) -> str:
    ext = "jpg" if fmt == "jpeg" else "png"
    if KEY_STRATEGY == "uuid":
        return f"{S3_PREFIX}{uuid.uuid4().hex}.{ext}"
    h = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}{h}.{ext}"


def s3_head(bucket: str, key: str):
    try:
        return s3.head_object(Bucket=bucket, Key=key)
    except ClientError as e:
        code = e.response.get("Error", {}).get("Code")
        if code in ("404", "NoSuchKey", "NotFound"):
            return None
        raise


def s3_put(bucket: str, key: str, body: bytes, fmt: str, meta: dict):
    extra = {
        "Bucket": bucket,
        "Key": key,
        "Body": body,
        "ContentType": content_type_for(fmt),
        "ACL": S3_ACL,
        "CacheControl": S3_CACHE_CONTROL,
        "Metadata": {k: str(v) for k, v in (meta or {}).items()},
    }
    if S3_SSE:
        extra["ServerSideEncryption"] = S3_SSE
    s3.put_object(**extra)


def s3_url(bucket: str, key: str) -> str:
    if PUBLIC_BASE_URL:
        base = PUBLIC_BASE_URL.rstrip("/")
        return f"{base}/{key}"
    return s3.generate_presigned_url(
        "get_object",
        Params={"Bucket": bucket, "Key": key},
        ExpiresIn=PRESIGN_EXPIRES,
    )


def build_chrome_driver():
    opts = Options()
    opts.add_argument(f"--window-size={VIEWPORT_WIDTH},{VIEWPORT_HEIGHT}")
    opts.add_argument("--headless=new")
    opts.add_argument("--disable-gpu")
    opts.add_argument("--hide-scrollbars")
    opts.add_argument("--force-color-profile=srgb")
    opts.add_argument("--lang=en-US")
    opts.add_argument("--mute-audio")
    opts.add_argument("--disable-background-networking")
    opts.add_argument("--disable-default-apps")
    opts.add_argument("--disable-extensions")
    opts.add_argument("--disable-sync")
    opts.add_argument("--metrics-recording-only")
    opts.add_argument("--no-first-run")
    opts.add_argument("--safebrowsing-disable-auto-update")
    opts.add_argument("--disable-features=Translate,BackForwardCache,AcceptCHFrame,MediaRouter")
    opts.add_argument("--blink-settings=imagesEnabled=true")
    if DISABLE_SANDBOX:
        opts.add_argument("--no-sandbox")
    if DISABLE_DEV_SHM:
        opts.add_argument("--disable-dev-shm-usage")
    if CHROME_BINARY:
        opts.binary_location = CHROME_BINARY
    service = ChromeService(executable_path=CHROMEDRIVER_PATH)
    driver = webdriver.Chrome(service=service, options=opts)
    driver.set_page_load_timeout(PAGELOAD_TIMEOUT)
    return driver


def build_phantomjs_driver():
    if not PHANTOMJS_PATH:
        raise RuntimeError("PHANTOMJS_PATH not set")
    caps = webdriver.DesiredCapabilities.PHANTOMJS.copy()
    caps["phantomjs.page.settings.userAgent"] = "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome Safari"
    driver = webdriver.PhantomJS(executable_path=PHANTOMJS_PATH, desired_capabilities=caps)
    driver.set_window_size(VIEWPORT_WIDTH, VIEWPORT_HEIGHT)
    driver.set_page_load_timeout(PAGELOAD_TIMEOUT)
    return driver


def wait_for_ready(driver):
    try:
        WebDriverWait(driver, min(10, PAGELOAD_TIMEOUT)).until(
            lambda d: d.execute_script("return document.readyState") in ("interactive", "complete")
        )
    except Exception:
        pass


def fullpage_resize_for_chrome(driver):
    try:
        height = driver.execute_script(
            "return Math.max(document.body.scrollHeight, document.documentElement.scrollHeight, "
            "document.body.offsetHeight, document.documentElement.offsetHeight, "
            "document.body.clientHeight, document.documentElement.clientHeight);"
        )
        height = int(height) if height else VIEWPORT_HEIGHT
        height = max(VIEWPORT_HEIGHT, min(height, 8000))
        driver.set_window_size(VIEWPORT_WIDTH, height)
    except Exception:
        pass


def take_screenshot_bytes(driver, fmt: str) -> bytes:
    if fmt == "png":
        return driver.get_screenshot_as_png()
    png = driver.get_screenshot_as_png()
    if Image is None:
        return png
    im = Image.open(io.BytesIO(png)).convert("RGB")
    out = io.BytesIO()
    im.save(out, format="JPEG", quality=JPEG_QUALITY, optimize=True)
    return out.getvalue()


def make_thumbnail(image_bytes: bytes, fmt: str) -> bytes:
    if Image is None:
        return image_bytes
    im = Image.open(io.BytesIO(image_bytes))
    if fmt == "jpeg":
        if im.mode not in ("RGB", "L"):
            im = im.convert("RGB")
    else:
        if im.mode not in ("RGBA", "RGB", "L"):
            im = im.convert("RGBA")
    im.thumbnail((THUMB_WIDTH, THUMB_HEIGHT), Image.Resampling.LANCZOS)
    out = io.BytesIO()
    if fmt == "png":
        im.save(out, format="PNG", optimize=True)
    else:
        im.save(out, format="JPEG", quality=JPEG_QUALITY, optimize=True)
    return out.getvalue()


def capture(url: str, engine: str, fmt: str) -> dict:
    driver = None
    started = time.time()
    try:
        if engine == "phantomjs":
            driver = build_phantomjs_driver()
        else:
            driver = build_chrome_driver()

        driver.get(url)
        wait_for_ready(driver)

        try:
            WebDriverWait(driver, 3).until(EC.presence_of_element_located((By.TAG_NAME, "body")))
        except Exception:
            pass

        if RENDER_WAIT_SECONDS > 0:
            time.sleep(RENDER_WAIT_SECONDS)

        if FULLPAGE and engine != "phantomjs":
            fullpage_resize_for_chrome(driver)
            if RENDER_WAIT_SECONDS > 0:
                time.sleep(min(0.5, RENDER_WAIT_SECONDS))

        raw = take_screenshot_bytes(driver, "png" if fmt == "png" else "png")
        thumb = make_thumbnail(raw, fmt)
        elapsed_ms = int((time.time() - started) * 1000)
        return {"image": thumb, "elapsed_ms": elapsed_ms}
    finally:
        if driver is not None:
            try:
                driver.quit()
            except Exception:
                pass


def auth_check():
    if not REQUIRE_TOKEN:
        return True
    token = request.headers.get("X-Api-Token") or request.args.get("token") or ""
    return bool(API_TOKEN) and token == API_TOKEN


