@app.route("/screenshot", methods=["POST", "GET"])
def screenshot():
    if not auth_check():
        return jsonify({"error": "unauthorized"}), 401

    data = {}
    if request.method == "POST":
        if request.is_json:
            data = request.get_json(silent=True) or {}
        else:
            data = request.form.to_dict() or {}
    else:
        data = request.args.to_dict() or {}

    raw_url = data.get("url") or data.get("u")
    engine = (data.get("engine") or "chrome").lower()
    fmt = (data.get("format") or OUTPUT_FORMAT).lower()
    refresh = str(data.get("refresh") or "0").lower() in ("1", "true", "yes")
    inline = str(data.get("inline") or "0").lower() in ("1", "true", "yes")

    if fmt not in ("jpeg", "png"):
        return jsonify({"error": "invalid format"}), 400
    if engine not in ("chrome", "phantomjs"):
        return jsonify({"error": "invalid engine"}), 400
    if not S3_BUCKET:
        return jsonify({"error": "S3_BUCKET not configured"}), 500

    try:
        url = normalize_url(raw_url)
    except Exception as e:
        return jsonify({"error": str(e)}), 400

    cached = cache_get(url)
    if cached and not refresh:
        payload = cached["payload"]
        if inline and payload.get("key"):
            obj = s3.get_object(Bucket=S3_BUCKET, Key=payload["key"])
            b = obj["Body"].read()
            return send_file(io.BytesIO(b), mimetype=content_type_for(fmt))
        return jsonify(payload)

    key = make_key(url, fmt)

    if not refresh:
        head = s3_head(S3_BUCKET, key)
        if head is not None:
            payload = {
                "ok": True,
                "url": url,
                "bucket": S3_BUCKET,
                "key": key,
                "image_url": s3_url(S3_BUCKET, key),
                "cached": True,
                "generated_at": head.get("LastModified").astimezone(timezone.utc).isoformat() if head.get("LastModified") else None,
            }
            cache_set(url, payload, DEDUP_TTL_SECONDS)
            if inline:
                obj = s3.get_object(Bucket=S3_BUCKET, Key=key)
                b = obj["Body"].read()
                return send_file(io.BytesIO(b), mimetype=content_type_for(fmt))
            return jsonify(payload)

    acquired = sem.acquire(timeout=PAGELOAD_TIMEOUT + 10)
    if not acquired:
        return jsonify({"error": "busy"}), 429

    try:
        res = capture(url, engine=engine, fmt=fmt)
        img = res["image"]
        meta = {
            "source_url": url,
            "engine": engine,
            "format": fmt,
            "thumb_width": THUMB_WIDTH,
            "thumb_height": THUMB_HEIGHT,
            "viewport": f"{VIEWPORT_WIDTH}x{VIEWPORT_HEIGHT}",
            "fullpage": str(bool(FULLPAGE)),
            "generated_at": utcnow_iso(),
        }
        s3_put(S3_BUCKET, key, img, fmt, meta)
        payload = {
            "ok": True,
            "url": url,
            "bucket": S3_BUCKET,
            "key": key,
            "image_url": s3_url(S3_BUCKET, key),
            "cached": False,
            "elapsed_ms": res.get("elapsed_ms"),
            "generated_at": meta["generated_at"],
        }
        cache_set(url, payload, DEDUP_TTL_SECONDS)
        if inline:
            return send_file(io.BytesIO(img), mimetype=content_type_for(fmt))
        return jsonify(payload)
    except Exception as e:
        logger.exception("screenshot error")
        return jsonify({"error": "capture_failed", "detail": str(e)}), 500
    finally:
        try:
            sem.release()
        except Exception:
            pass


